using Microsoft.ML.Data;

namespace TicketClassifier.Models;

public class TicketData
{
    [LoadColumn(0)]
    public string Subject { get; set; } = string.Empty;

    [LoadColumn(1)]
    public string Description { get; set; } = string.Empty;

    [LoadColumn(2)]
    public float Priority { get; set; }

    [LoadColumn(3)]
    public string Category { get; set; } = string.Empty;
}

public class TicketPrediction
{
    [ColumnName("PredictedLabel")]
    public string Category { get; set; } = string.Empty;

    public float[] Score { get; set; } = [];
}

namespace TicketClassifier.Models;

public class TicketRequest
{
    public string Subject { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public int Priority { get; set; }
}

public class TicketPredictionResponse
{
    public string PredictedCategory { get; set; } = string.Empty;
    public Dictionary<string, float> Confidence { get; set; } = new();
}

using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public class ModelTrainingService
{
    private readonly MLContext _mlContext;
    private readonly string _dataPath;
    private readonly string _modelPath;
    private readonly ILogger<ModelTrainingService> _logger;

    public ModelTrainingService(ILogger<ModelTrainingService> logger)
    {
        _mlContext = new MLContext(seed: 42);
        _dataPath = Path.Combine(AppContext.BaseDirectory, "Data", "tickets.csv");
        _modelPath = Path.Combine(AppContext.BaseDirectory, "Data", "model.zip");
        _logger = logger;
    }

    public string ModelPath => _modelPath;

    public void TrainAndEvaluate()
    {
        var data = _mlContext.Data.LoadFromTextFile<TicketData>(
            _dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        var split = _mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: 42);

        var pipeline = _mlContext.Transforms.Text.FeaturizeText("SubjectFeaturized", nameof(TicketData.Subject))
            .Append(_mlContext.Transforms.Text.FeaturizeText("DescriptionFeaturized", nameof(TicketData.Description)))
            .Append(_mlContext.Transforms.Concatenate("Features", "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketData.Priority)))
            .Append(_mlContext.Transforms.Conversion.MapValueToKey("Label", nameof(TicketData.Category)))
            .Append(_mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy("Label", "Features"))
            .Append(_mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

        _logger.LogInformation("Training model...");
        var model = pipeline.Fit(split.TrainSet);

        var predictions = model.Transform(split.TestSet);
        var metrics = _mlContext.MulticlassClassification.Evaluate(predictions);

        _logger.LogInformation("=== Model Evaluation Metrics ===");
        _logger.LogInformation("Macro Accuracy:    {MacroAccuracy:F4}", metrics.MacroAccuracy);
        _logger.LogInformation("Micro Accuracy:    {MicroAccuracy:F4}", metrics.MicroAccuracy);
        _logger.LogInformation("Log Loss:          {LogLoss:F4}", metrics.LogLoss);
        _logger.LogInformation("Log Loss Reduction:{LogLossReduction:F4}", metrics.LogLossReduction);

        _mlContext.Model.Save(model, split.TrainSet.Schema, _modelPath);
        _logger.LogInformation("Model saved to {Path}", _modelPath);
    }
}

using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketController : ControllerBase
{
    private readonly PredictionEnginePool<TicketData, TicketPrediction> _predictionPool;

    public TicketController(PredictionEnginePool<TicketData, TicketPrediction> predictionPool)
    {
        _predictionPool = predictionPool;
    }

    [HttpPost("classify")]
    public ActionResult<TicketPredictionResponse> Classify([FromBody] TicketRequest request)
    {
        if (string.IsNullOrWhiteSpace(request.Subject) && string.IsNullOrWhiteSpace(request.Description))
            return BadRequest("Subject or Description is required.");

        if (request.Priority < 1 || request.Priority > 3)
            return BadRequest("Priority must be between 1 and 3.");

        var input = new TicketData
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = _predictionPool.Predict(input);

        var labels = new[] { "Billing", "General", "Technical" };
        var confidence = new Dictionary<string, float>();
        for (int i = 0; i < labels.Length && i < prediction.Score.Length; i++)
        {
            confidence[labels[i]] = prediction.Score[i];
        }

        return Ok(new TicketPredictionResponse
        {
            PredictedCategory = prediction.Category,
            Confidence = confidence
        });
    }
}

